// Multi-business context aggregator
// Fetches all data, then splits/filters by business_id to produce per-business context rows

const contextRows = [];

function safeArrayAll(nodeName) {
  try {
    const items = $(nodeName).all();
    const first = items[0] && items[0].json;
    if (Array.isArray(first)) return first;
    return items.map(i => i.json).filter(i => i && Object.keys(i).length > 0);
  } catch (e) {
    return [];
  }
}

function filterByBiz(arr, bizUuid, bizSlug) {
  return arr.filter(function(item) {
    return item.business_id === bizUuid || item.business_id === bizSlug;
  });
}

const now = new Date();
const sevenDaysAgo = new Date(now);
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

// Load all raw data once
const allBizRecords = safeArrayAll('Fetch All Businesses');
const allMetrics = safeArrayAll('Fetch Daily Metrics (All)');
const allLeads = safeArrayAll('Fetch Pipeline Leads');
const allCalls = safeArrayAll('Fetch Voice Calls');
const allContent = safeArrayAll('Fetch Content Performance');
const allKeywords = safeArrayAll('Fetch Keyword Performance');
const allBudgets = safeArrayAll('Fetch Budget Tracking (All)');
const allOpps = safeArrayAll('Fetch Pending Opportunities');
const allActivities = safeArrayAll('Fetch Recent Activities');
const allEmailLog = safeArrayAll('Fetch Email Log');

// Iterate over each active business
for (const biz of allBizRecords) {
  const bizUuid = biz.id;
  const businessId = biz.business_id || 'unknown';

  // Filter all data for this business
  const metrics = filterByBiz(allMetrics, bizUuid, businessId).slice(0, 7);
  const leads = filterByBiz(allLeads, bizUuid, businessId);
  const calls = filterByBiz(allCalls, bizUuid, businessId);
  const content = filterByBiz(allContent, bizUuid, businessId).slice(0, 50);
  const keywords = filterByBiz(allKeywords, bizUuid, businessId).slice(0, 30);
  const budgets = filterByBiz(allBudgets, bizUuid, businessId).slice(0, 7);
  const activities = filterByBiz(allActivities, bizUuid, businessId);
  const emailLog = filterByBiz(allEmailLog, bizUuid, businessId);

  // 1. PIPELINE SUMMARY
  var statusCounts = {};
  for (var li = 0; li < leads.length; li++) {
    var s = leads[li].status || 'new';
    statusCounts[s] = (statusCounts[s] || 0) + 1;
  }
  contextRows.push({
    business_id: businessId,
    context_key: 'pipeline_summary',
    context_value: {
      total_leads: leads.length,
      new: statusCounts['new'] || 0,
      contacted: (statusCounts['contacted'] || 0) + (statusCounts['follow_up_1'] || 0) + (statusCounts['follow_up_2'] || 0),
      replied: statusCounts['replied'] || 0,
      demo_booked: leads.filter(function(l) { return l.demo_date; }).length,
      converted: statusCounts['converted'] || 0,
      completed: statusCounts['completed'] || 0,
      unsubscribed: statusCounts['unsubscribed'] || 0
    }
  });

  // 2. REVENUE SUMMARY
  var last7Revenue = 0;
  for (var i = 0; i < metrics.length; i++) {
    var m = metrics[i];
    last7Revenue += Number(m.revenue_organic || 0) + Number(m.revenue_paid || 0) + Number(m.revenue_direct || 0) + Number(m.revenue_referral || 0);
  }
  contextRows.push({
    business_id: businessId,
    context_key: 'revenue_summary',
    context_value: {
      mrr: Number(biz.current_mrr || 0),
      total_revenue: Number(biz.total_revenue || 0),
      last_7_days_revenue: last7Revenue,
      total_capital_deployed: Number(biz.total_capital_deployed || 0),
      status: biz.status || 'unknown'
    }
  });

  // 3. TRAFFIC SUMMARY
  var yesterday = metrics[0] || {};
  var dayBefore = metrics[1] || {};
  var yesterdayTraffic = Number(yesterday.traffic_total || 0);
  var dayBeforeTraffic = Number(dayBefore.traffic_total || 0);
  var trend = 'flat';
  if (yesterdayTraffic > dayBeforeTraffic * 1.1) trend = 'up';
  else if (yesterdayTraffic < dayBeforeTraffic * 0.9) trend = 'down';
  var last7Signups = 0, last7Churn = 0, last7Traffic = 0;
  for (var j = 0; j < metrics.length; j++) {
    last7Signups += Number(metrics[j].signups || 0);
    last7Churn += Number(metrics[j].churn_count || 0);
    last7Traffic += Number(metrics[j].traffic_total || 0);
  }
  contextRows.push({
    business_id: businessId,
    context_key: 'traffic_summary',
    context_value: {
      yesterday_visitors: yesterdayTraffic,
      yesterday_organic: Number(yesterday.traffic_organic || 0),
      yesterday_paid: Number(yesterday.traffic_paid || 0),
      yesterday_direct: Number(yesterday.traffic_direct || 0),
      yesterday_referral: Number(yesterday.traffic_referral || 0),
      last_7_days_total: last7Traffic,
      last_7_days_signups: last7Signups,
      last_7_days_churn: last7Churn,
      trend: trend
    }
  });

  // 4. CONTENT SUMMARY
  var totalImpressions = 0, totalClicks = 0, totalSignupsFromContent = 0;
  for (var k = 0; k < content.length; k++) {
    totalImpressions += Number(content[k].impressions || 0);
    totalClicks += Number(content[k].clicks || 0);
    totalSignupsFromContent += Number(content[k].signups_attributed || 0);
  }
  contextRows.push({
    business_id: businessId,
    context_key: 'content_summary',
    context_value: {
      total_posts: content.length,
      total_impressions: totalImpressions,
      total_clicks: totalClicks,
      total_signups_attributed: totalSignupsFromContent,
      ctr_pct: totalImpressions > 0 ? Math.round((totalClicks / totalImpressions) * 10000) / 100 : 0,
      top_post: content.length > 0 ? content[0].title : 'none'
    }
  });

  // 5. EMAIL SUMMARY
  var recentEmails = emailLog.filter(function(e) {
    return e.sent_at && new Date(e.sent_at) >= sevenDaysAgo;
  });
  var repliedLeads = leads.filter(function(l) { return l.status === 'replied'; });
  var positiveLeads = leads.filter(function(l) { return l.reply_sentiment === 'positive'; });
  contextRows.push({
    business_id: businessId,
    context_key: 'email_summary',
    context_value: {
      sent_last_7_days: recentEmails.length,
      total_replied: repliedLeads.length,
      reply_rate_pct: recentEmails.length > 0 ? Math.round((repliedLeads.length / recentEmails.length) * 10000) / 100 : 0,
      positive_rate_pct: repliedLeads.length > 0 ? Math.round((positiveLeads.length / repliedLeads.length) * 10000) / 100 : 0
    }
  });

  // 6. CALL SUMMARY
  var recentCalls = calls.filter(function(c) {
    return c.created_at && new Date(c.created_at) >= sevenDaysAgo;
  });
  var totalCalls = recentCalls.length;
  var connected = recentCalls.filter(function(c) { return c.outcome && c.outcome !== 'no_answer' && c.outcome !== 'voicemail'; });
  var booked = recentCalls.filter(function(c) { return c.booking_made === true; });
  contextRows.push({
    business_id: businessId,
    context_key: 'call_summary',
    context_value: {
      calls_last_7_days: totalCalls,
      connected: connected.length,
      connect_rate_pct: totalCalls > 0 ? Math.round((connected.length / totalCalls) * 10000) / 100 : 0,
      bookings: booked.length,
      booking_rate_pct: totalCalls > 0 ? Math.round((booked.length / totalCalls) * 10000) / 100 : 0
    }
  });

  // 7. KEYWORD SUMMARY
  var top10 = keywords.filter(function(kw) { return kw.current_position && kw.current_position <= 10; });
  var top3 = keywords.filter(function(kw) { return kw.current_position && kw.current_position <= 3; });
  var ranked = keywords.filter(function(kw) { return kw.current_position && kw.current_position <= 100; });
  contextRows.push({
    business_id: businessId,
    context_key: 'keyword_summary',
    context_value: {
      total_tracked: keywords.length,
      ranking_top_3: top3.length,
      ranking_top_10: top10.length,
      ranking_top_100: ranked.length,
      top_keywords: top10.slice(0, 5).map(function(kw) { return { keyword: kw.keyword, position: kw.current_position, volume: kw.search_volume }; })
    }
  });

  // 8. BUDGET SUMMARY
  var latestBudget = budgets[0] || {};
  var totalSpent7d = 0, totalRevenue7d = 0;
  for (var b = 0; b < budgets.length; b++) {
    totalSpent7d += Number(budgets[b].total_spend || 0);
    totalRevenue7d += Number(budgets[b].revenue || 0);
  }
  contextRows.push({
    business_id: businessId,
    context_key: 'budget_summary',
    context_value: {
      daily_budget_limit: Number(latestBudget.daily_budget_limit || 0),
      today_spend: Number(latestBudget.total_spend || 0),
      today_balance: Number(latestBudget.balance || 0),
      last_7_days_spend: totalSpent7d,
      last_7_days_revenue: totalRevenue7d,
      circuit_breaker_triggered: latestBudget.circuit_breaker_triggered || false
    }
  });

  // 9. ACTIVITY SUMMARY
  var recentActivities = activities.filter(function(a) {
    return a.created_at && new Date(a.created_at) >= sevenDaysAgo;
  });
  var activityCounts = {};
  for (var x = 0; x < recentActivities.length; x++) {
    var t = recentActivities[x].activity_type || 'unknown';
    activityCounts[t] = (activityCounts[t] || 0) + 1;
  }
  contextRows.push({
    business_id: businessId,
    context_key: 'activity_summary',
    context_value: {
      total_activities_7d: recentActivities.length,
      by_type: activityCounts,
      most_recent: recentActivities.slice(0, 5).map(function(a) {
        return { type: a.activity_type, channel: a.channel, at: a.created_at };
      })
    }
  });
}

// 10. OPPORTUNITIES SUMMARY (portfolio-level, not per-business)
contextRows.push({
  business_id: 'portfolio',
  context_key: 'opportunities_summary',
  context_value: {
    pending_count: allOpps.length,
    top_opportunities: allOpps.slice(0, 5).map(function(o) {
      return {
        category: o.category,
        description: (o.description || '').substring(0, 100),
        score: o.ai_score,
        status: o.status
      };
    })
  }
});

return contextRows.map(function(row) { return { json: row }; });
